 1	import React, { FC, useMemo } from 'react';
 2	import { useLocation, useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { Tab, Tabs, TabTitleText } from '@patternfly/react-core';
 5	import { ALL_NAMESPACES } from '@utils/constants';
 6	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 7	
 8	import useIsMultiEnabled from './hooks/useIsMultiEnabled';
 9	import { TAB_INDEXES } from './constants';
10	import EnableMultiPage from './EnableMultiPage';
11	import MultiNetworkPolicyList from './MultiNetworkPolicyList';
12	import NetworkPolicyList from './NetworkPolicyList';
13	import { getActiveKeyFromPathname, getNetworkPolicyURLTab } from './utils';
14	
15	export type NetworkPolicyPageNavProps = {
16	  namespace: string;
17	};
18	
19	const NetworkPolicyDetailsPage: FC<NetworkPolicyPageNavProps> = ({ namespace }) => {
20	  const navigate = useNavigate();
21	  const location = useLocation();
22	
23	  const locationTabKey = useMemo(
24	    () => getActiveKeyFromPathname(location?.pathname),
25	    [location?.pathname],
26	  );
27	
28	  const [isMultiEnabled] = useIsMultiEnabled();
29	  const { t } = useNetworkingTranslation();
30	
31	  return (
32	    <Tabs
33	      activeKey={locationTabKey}
34	      onSelect={(_, tabIndex: number | string) => {
35	        navigate(getNetworkPolicyURLTab(tabIndex, namespace || ALL_NAMESPACES));
36	      }}
37	    >
38	      <Tab
39	        eventKey={TAB_INDEXES.NETWORK}
40	        title={<TabTitleText>{t('NetworkPolicies')}</TabTitleText>}
41	      >
42	        <NetworkPolicyList namespace={namespace} />
43	      </Tab>
44	      {isMultiEnabled ? (
45	        <Tab
46	          eventKey={TAB_INDEXES.MULTI_NETWORK}
47	          title={<TabTitleText>{t('MultiNetworkPolicies')}</TabTitleText>}
48	        >
49	          <MultiNetworkPolicyList namespace={namespace} />
50	        </Tab>
51	      ) : (
52	        <Tab
53	          eventKey={TAB_INDEXES.ENABLE_MULTI}
54	          title={<TabTitleText>{t('MultiNetworkPolicies')}</TabTitleText>}
55	        >
56	          <EnableMultiPage />
57	        </Tab>
58	      )}
59	    </Tabs>
60	  );
61	};
62	
63	export default NetworkPolicyDetailsPage;

