 1	import { modelToRef, NetworkPolicyModel } from '@kubevirt-ui/kubevirt-api/console';
 2	import { ALL_NAMESPACES } from '@utils/constants';
 3	import { MultiNetworkPolicyModel } from '@utils/models';
 4	
 5	import { TAB_INDEXES } from './constants';
 6	
 7	export const getActiveKeyFromPathname = (pathname: string) => {
 8	  if (pathname.endsWith(MultiNetworkPolicyModel.kind)) return TAB_INDEXES.MULTI_NETWORK;
 9	
10	  if (pathname.includes('enable-multi')) return TAB_INDEXES.ENABLE_MULTI;
11	
12	  return TAB_INDEXES.NETWORK;
13	};
14	
15	export const getNetworkPolicyURLTab = (tabIndex: number | string, namespace: string): string => {
16	  const namespacePath = namespace === ALL_NAMESPACES ? namespace : `ns/${namespace}`;
17	
18	  if (tabIndex === TAB_INDEXES.ENABLE_MULTI) {
19	    return `/k8s/${namespacePath}/${modelToRef(NetworkPolicyModel)}/enable-multi`;
20	  }
21	
22	  return `/k8s/${namespacePath}/${tabIndex === TAB_INDEXES.NETWORK ? modelToRef(NetworkPolicyModel) : modelToRef(MultiNetworkPolicyModel)}`;
23	};

